from opentelemetry import metrics

meter = metrics.get_meter("genai.service")
parse_attempts = meter.create_counter(
    "genai.parse_attempts_total",
    description="Total structured output parse attempts"
)
parse_failures = meter.create_counter(
    "genai.parse_failures_total",
    description="Total structured output parse failures"
)

def parse_tool_call(raw: str, schema: type) -> dict:
    parse_attempts.add(1)
    try:
        return schema.model_validate_json(raw)
    except Exception as e:
        parse_failures.add(1, {"error_type": type(e).__name__})
        raise
